def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    # Mapping predicates to phrase generators
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"was created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"founded by {o}"
    def key_person(s, o): return f"key person {o}"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"distributed by {o}"
    def birth_place(s, o): return f"born in {o}"
    def nationality(s, o):
        # Normalize nationality values
        if "United States" in o:
            return f"is American"
        elif "nationality" in o.lower() or "national" in o.lower():
            return f"has {o} nationality"
        else:
            return f"is {o}"
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Identify main subject (typically the comicsCharacter)
    main_subject = None
    other_subjects = []
    for subject in subject_triples.keys():
        if "comicsCharacter" in subject or "Character" in subject:
            main_subject = subject
        else:
            other_subjects.append(subject)

    if main_subject is None and subject_triples:
        main_subject = list(subject_triples.keys())[0]
        other_subjects = list(subject_triples.keys())[1:]

    # Build the main clause for the primary subject
    main_triples = subject_triples.get(main_subject, [])

    # Collect main subject predicates
    main_clauses = []
    for t in main_triples:
        func = phrase_funcs.get(t.predicate)
        if func:
            main_clauses.append(func(main_subject, t.object))
        else:
            main_clauses.append(f"{t.predicate} {t.object}")

    # Build main sentence
    if main_clauses:
        if len(main_clauses) == 1:
            main_sentence = f"{main_subject} {main_clauses[0]}"
        else:
            main_sentence = f"{main_subject} {', '.join(main_clauses[:-1])} and {main_clauses[-1]}"
    else:
        main_sentence = main_subject

    # Build relative clauses for other subjects
    if other_subjects:
        for subject in other_subjects:
            triples_for_subject = subject_triples[subject]
            subject_clauses = []
            for t in triples_for_subject:
                func = phrase_funcs.get(t.predicate)
                if func:
                    subject_clauses.append(func(subject, t.object))
                else:
                    subject_clauses.append(f"{t.predicate} {t.object}")

            if subject_clauses:
                if len(subject_clauses) == 1:
                    relative_clause = f", who {subject_clauses[0]}" if is_person(subject) else f", which {subject_clauses[0]}"
                else:
                    clause_text = f"{', '.join(subject_clauses[:-1])} and {subject_clauses[-1]}"
                    relative_clause = f", who {clause_text}" if is_person(subject) else f", which {clause_text}"
                main_sentence += relative_clause

    return main_sentence + "."

def is_person(subject: str) -> bool:
    """Check if subject is likely a person based on common patterns."""
    person_indicators = ["comicsCharacter", "Character", "actor", "voice", "creator", "born", "creator"]
    non_person_indicators = ["film", "airport", "city", "building", "company", "BBC", "Radio"]

    # Check if it's clearly not a person
    if any(indicator in subject for indicator in non_person_indicators):
        return False

    # Check if it's clearly a person
    return any(indicator in subject for indicator in person_indicators)

